<script setup>
import PatternCard from '../PatternCard.vue'

const codes = {"Java": "<span class=\"kw\">public class</span> <span class=\"cl\">Singleton</span> {\n  <span class=\"kw\">private static volatile</span> <span class=\"cl\">Singleton</span> <span class=\"dc\">inst</span>;\n  <span class=\"kw\">private</span> <span class=\"cl\">Singleton</span>() {}\n\n  <span class=\"kw\">public static</span> <span class=\"cl\">Singleton</span> <span class=\"fn\">get</span>() {\n    <span class=\"kw\">if</span> (<span class=\"dc\">inst</span> == <span class=\"kw\">null</span>)\n      <span class=\"kw\">synchronized</span> (<span class=\"cl\">Singleton</span>.<span class=\"kw\">class</span>) {\n        <span class=\"kw\">if</span> (<span class=\"dc\">inst</span> == <span class=\"kw\">null</span>)\n          <span class=\"dc\">inst</span> = <span class=\"kw\">new</span> <span class=\"cl\">Singleton</span>();\n      }\n    <span class=\"kw\">return</span> <span class=\"dc\">inst</span>;\n  }\n\n  <span class=\"kw\">public void</span> <span class=\"fn\">log</span>(<span class=\"cl\">String</span> <span class=\"dc\">msg</span>) {\n    <span class=\"cl\">System</span>.out.<span class=\"fn\">println</span>(<span class=\"st\">\"[LOG] \"</span> + <span class=\"dc\">msg</span>);\n  }\n}\n\n<span class=\"cm\">// Uso</span>\n<span class=\"cl\">Singleton</span>.<span class=\"fn\">get</span>().<span class=\"fn\">log</span>(<span class=\"st\">\"App iniciado\"</span>);", "CSharp": "<span class=\"kw\">public sealed class</span> <span class=\"cl\">Singleton</span> {\n  <span class=\"kw\">static readonly</span> <span class=\"cl\">Lazy</span>&lt;<span class=\"cl\">Singleton</span>&gt; <span class=\"dc\">_instance</span> =\n    <span class=\"kw\">new</span>(() =&gt; <span class=\"kw\">new</span> <span class=\"cl\">Singleton</span>());\n\n  <span class=\"kw\">private</span> <span class=\"cl\">Singleton</span>() {}\n\n  <span class=\"kw\">public static</span> <span class=\"cl\">Singleton</span> <span class=\"dc\">Instance</span> =&gt; <span class=\"dc\">_instance</span>.<span class=\"dc\">Value</span>;\n\n  <span class=\"kw\">public void</span> <span class=\"fn\">Log</span>(<span class=\"kw\">string</span> <span class=\"dc\">msg</span>) =&gt;\n    <span class=\"cl\">Console</span>.<span class=\"fn\">WriteLine</span>(<span class=\"st\">$\"[LOG] {{msg}}\"</span>);\n}\n\n<span class=\"cm\">// Uso</span>\n<span class=\"cl\">Singleton</span>.<span class=\"dc\">Instance</span>.<span class=\"fn\">Log</span>(<span class=\"st\">\"App iniciado\"</span>);", "Python": "<span class=\"kw\">class</span> <span class=\"cl\">SingletonMeta</span>(<span class=\"kw\">type</span>):\n  <span class=\"dc\">_instances</span>: <span class=\"kw\">dict</span> = {}\n\n  <span class=\"kw\">def</span> <span class=\"fn\">__call__</span>(<span class=\"dc\">cls</span>, *<span class=\"dc\">args</span>, **<span class=\"dc\">kwargs</span>):\n    <span class=\"kw\">if</span> <span class=\"dc\">cls</span> <span class=\"kw\">not in</span> <span class=\"dc\">cls._instances</span>:\n      <span class=\"dc\">cls._instances</span>[<span class=\"dc\">cls</span>] = <span class=\"kw\">super</span>().<span class=\"fn\">__call__</span>(\n        *<span class=\"dc\">args</span>, **<span class=\"dc\">kwargs</span>)\n    <span class=\"kw\">return</span> <span class=\"dc\">cls._instances</span>[<span class=\"dc\">cls</span>]\n\n\n<span class=\"kw\">class</span> <span class=\"cl\">Logger</span>(metaclass=<span class=\"cl\">SingletonMeta</span>):\n  <span class=\"kw\">def</span> <span class=\"fn\">log</span>(<span class=\"dc\">self</span>, <span class=\"dc\">msg</span>):\n    <span class=\"fn\">print</span>(<span class=\"st\">f\"[LOG] {{msg}}\"</span>)\n\n\n<span class=\"cm\"># s1 is s2  \u2192  True</span>\n<span class=\"dc\">s1</span>, <span class=\"dc\">s2</span> = <span class=\"cl\">Logger</span>(), <span class=\"cl\">Logger</span>()\n<span class=\"kw\">assert</span> <span class=\"dc\">s1</span> <span class=\"kw\">is</span> <span class=\"dc\">s2</span>", "Ruby": "<span class=\"kw\">require</span> <span class=\"st\">'singleton'</span>\n\n<span class=\"kw\">class</span> <span class=\"cl\">AppLogger</span>\n  <span class=\"kw\">include</span> <span class=\"cl\">Singleton</span>\n\n  <span class=\"kw\">def</span> <span class=\"fn\">log</span>(<span class=\"dc\">msg</span>)\n    <span class=\"fn\">puts</span> <span class=\"st\">\"[LOG] #{{msg}}\"</span>\n  <span class=\"kw\">end</span>\n<span class=\"kw\">end</span>\n\n<span class=\"cm\"># Uso</span>\n<span class=\"dc\">logger</span> = <span class=\"cl\">AppLogger</span>.<span class=\"fn\">instance</span>\n<span class=\"dc\">logger</span>.<span class=\"fn\">log</span>(<span class=\"st\">\"App iniciado\"</span>)"}

